import { PrismaClient } from '@prisma/client';
import { RedisClient } from 'redis';
import { Kafka } from 'kafkajs';

const prisma = new PrismaClient();
const redisClient = new RedisClient();
const kafka = new Kafka({ brokers: ['localhost:9092'] });

async function validateUser(username: string, password: string): Promise<boolean> {
    // Validate inputs
    if (!username || !password) {
        throw new Error('Username and password are required');
    }

    // Check Redis cache first
    const cachedUser = await getUserFromCache(username);
    if (cachedUser) {
        return cachedUser.password === password;
    }

    // Fetch user from database
    const user = await prisma.user.findUnique({
        where: { username },
    });

    if (!user) {
        return false;
    }

    // Validate password (assuming a function validatePassword exists)
    const isValid = validatePassword(password, user.password);
    if (isValid) {
        await cacheUser(username, user.password);
    }

    return isValid;
}

async function getUserFromCache(username: string): Promise<any> {
    return new Promise((resolve, reject) => {
        redisClient.get(username, (err, result) => {
            if (err) {
                return reject(err);
            }
            resolve(result ? JSON.parse(result) : null);
        });
    });
}

async function cacheUser(username: string, password: string): Promise<void> {
    const user = { username, password };
    redisClient.set(username, JSON.stringify(user), 'EX', 3600); // Cache for 1 hour
}

function validatePassword(inputPassword: string, storedPassword: string): boolean {
    // Implement password validation logic (e.g., hashing comparison)
    return inputPassword === storedPassword; // Simplified for example
}

// Kafka producer example
async function produceLoginEvent(username: string): Promise<void> {
    const producer = kafka.producer();
    await producer.connect();
    await producer.send({
        topic: 'login-events',
        messages: [{ value: `User ${username} logged in` }],
    });
    await producer.disconnect();
}

// Example usage
async function login(username: string, password: string) {
    const isValid = await validateUser(username, password);
    if (isValid) {
        await produceLoginEvent(username);
    }
    return isValid;
}

export { login };
